#include<bits/stdc++.h>
#define LL long long
#define LD long double
#define Uint unsigned int
#define ULL unsigned LL
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 5e5+5;
int n,a[N],cnt1,Ans;
priority_queue<int,vector<int>,greater<int>> q;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void Count(){
    int cnt=(cnt1+q.size())/2;
    int res=min(cnt,cnt1)+max(0,cnt-cnt1)*2;
    Ans=min(Ans,res);return;
}
int main(){
    n=read(),Ans=n;
    for(int i=1;i<=n;i++)a[i]=read();
    for(int i=1;i<=n;i++)
        if(a[i]==1)cnt1++;else q.push(a[i]);
    while(!q.empty()&&cnt1+q.size()<=2*n){
        Count();
        int x=q.top();q.pop();
        cnt1++;
        if(x-1==1)cnt1++;
        else q.push(x-1);
    }Count();
    cout<<Ans<<"\n";
    return 0;
}
